const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Business', 'Aperçu de l\'entreprise', 'Entreprise'],
    ['Market', 'Opportunité de marché', 'Marché'],
    ['Solution'],
    ['Team', 'Équipe'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const sectionId = body.section_id;
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Aperçu de l'entreprise
- Opportunité de marché
- Notre solution
- Équipe et leadership
` : `
- Business Overview
- Market Opportunity
- Our Solution
- Team & Leadership
`;

// Use only MEMORY_SUMMARY from each section to stay within 8K token limit
// Your frontend should send memory_summary strings in plan_context, not full prose
const prompt = `
You are a senior business consultant writing a professional business plan.

Your task: Write the "Executive Summary" section — the final synthesis of a completed business plan.
Output language: ${language}

## COMPANY PRESENTATION
${context.company_presentation || 'Not provided'}

## MARKET ANALYSIS
${context.market_analysis || 'Not provided'}

## ORGANIZATION & MANAGEMENT
${context.org_management || 'Not provided'}

## STRATEGY
${context.strategy || 'Not provided'}

## OPERATIONAL PLAN
${context.operational_plan || 'Not provided'}

## FINANCIAL PLAN
${context.financial_plan || 'Not provided'}

## RISK & OPPORTUNITY
${context.risk_opportunity || 'Not provided'}

## APPENDICES
${context.appendices || 'Not provided'}

## RULES
- Synthesize ONLY from the context sections above. Do NOT introduce new facts, figures, or claims not present in the context.
- Every statement MUST be traceable to at least one context section above.
- Do NOT repeat verbatim content — distill into sharp, persuasive prose.
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.
- Financial figures (revenue, costs, profit, breakeven) MUST match EXACTLY the values in the Financial Plan context. Do not round or restate them differently.
- Open with a single punchy paragraph (3–4 sentences max) stating: what the company does, who it serves, what makes it different, and why now. Do NOT open with the company name or founding date.
- Do NOT open with the problem statement alone — balance problem + solution + opportunity.
- Avoid these generic phrases entirely: "poised to capitalize", "committed to innovation", "unique value proposition", "well-positioned", "high-quality product". Replace with specific facts and figures.
- The tone MUST be confident and investor-facing throughout.
- Write at least 400 words.
- Use formal, compelling business language.
- Structure using these headings: ${headings}

## OUTPUT FORMAT
Return your response using EXACTLY this structure. Nothing before. Nothing after.

=== SECTION_TEXT ===
[Write the full Executive Summary here, using the headings above]

=== MEMORY_SUMMARY ===
Business Concept: [1-sentence: what the company does and for whom]
Market Opportunity: [1-sentence: market size and target segment with exact figures]
Competitive Edge: [1-sentence: specific differentiator — no generic phrases]
Revenue Model: [1-sentence with actual pricing figures from strategy context]
Financial Highlight: [Y1/Y2/Y3 revenue figures + breakeven month — exact values]
Funding Ask: [value or "Self-funded"]
Risk Flag: [top risk in 5 words or fewer]
Profitability Status: [copy exactly from Financial Plan context]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'executive_summary',
    language,
  }
}];

const raw = $('AI Agent').item.json.output || '';

// Remove MEMORY_SUMMARY block from display text
const textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
const memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

let section_text = textMatch 
    ? textMatch[1].trim() 
    : raw.replace(/=== MEMORY_SUMMARY ===([\s\S]*?)$/, '').trim();

// Also strip any stray === headings === from section text
section_text = section_text.replace(/===\s*.*?\s*===/g, '').trim();

const memory_summary = memMatch ? memMatch[1].trim() : '';

const promptText    = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
return [{
    json: {
        ...buildData,
        output: section_text,
        memory_summary: null,
        tokens_input,
        tokens_output,
        tokens_total,
    }
}];
